import { Grid, Paper,Stack,Button,Typography,  } from '@mui/material'
import React from 'react'
import { useNavigate } from 'react-router-dom'
import signpng from './signupfinal.png'



import { makeStyles } from '@mui/styles';

const useStyles = makeStyles((theme) => ({
  image: {
    width: 'auto',
    height: '600px',
  },
}));


export const Signup = () => {
    const navigate = useNavigate()
    const classes = useStyles();

return (
    <Grid container
    justifyContent="center"
    alignItems="center"
    style={{ minHeight: '100vh' }}>


        <Paper sx={{padding:'0px', width: '1200px', height: '600px'}} elevation={10}>
            
        <Stack  spacing={200} direction='row'>
        <img src={signpng} alt='The signup ' className={classes.image}  />
        
        <Stack direction='vertical' justifyContent='center' alignItems='center'>
        
        <Typography variant='h2'>Hello world how are you</Typography>
        <Button variant='contained' onClick={()=>{navigate('/signup')}}>Signup</Button>
        </Stack>
    </Stack>


        </Paper>


    </Grid>
  )
}
